#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <signal.h>
#include <setjmp.h>
#include <string.h>

static jmp_buf jump_buf;
static void handler(int sig) { (void)sig; longjmp(jump_buf, 1); }

int main(void) {
    size_t ps = (size_t)getpagesize();
    char *mem = (char *)mmap(NULL, ps, PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (mem == MAP_FAILED) { perror("mmap"); return 1; }
    strcpy(mem, "writable");
    printf("Before protect: %s\n", mem);
    int rc = ____(mem, ps, ____);
    printf("mprotect result: %d\n", rc);
    printf("Read after protect: %s\n", mem);
    signal(SIGSEGV, handler);
    if (setjmp(jump_buf) == 0) {
        mem[0] = 'X';
        printf("Write succeeded\n");
    } else {
        printf("Write blocked: SIGSEGV caught\n");
    }
    ____(mem, ps, PROT_READ | PROT_WRITE);
    mem[0] = 'W';
    printf("After restore: %c%s\n", mem[0], mem + 1);
    munmap(mem, ps);
    return 0;
}

